fn parse_target(to: &str) -> Result<StoreType> {
    match to.to_lowercase().as_str() {
        "lite" => Ok(StoreType::Lite),
        "postgres" | "postgresql" | "pg" => Ok(StoreType::Postgres),
        other => anyhow::bail!(
            "Unknown store type '{other}'. Valid targets: lite, postgres"
        ),
    }
}
